AreaConfig = {}
AreaConfig.Areas = {}

function AreaConfig:init(config)
    for id, area in pairs(config) do
        local item = {}
        item.id = tonumber(id)
        local spos = StringUtil.split(area.startPos, "#")
        item.startPos = VectorUtil.newVector3(spos[1], spos[2], spos[3])
        local epos = StringUtil.split(area.endPos, "#")
        item.endPos = VectorUtil.newVector3(epos[1], epos[2], epos[3])
        item.waitShrinkTime = tonumber(area.waitShrinkTime)
        item.shrinkTime = tonumber(area.shrinkTime)
        item.waitCreatTime = tonumber(area.waitCreatTime)
        item.bleedValue = tonumber(area.bleedValue)
        item.fatherArea = StringUtil.split(area.fatherArea, "#")
        self.Areas[item.id] = item
    end
end

function AreaConfig:getAreaById(id)
    local area = self.Areas[tonumber(id)]
    if area ~= nil then
        return area
    end
    return nil
end

function AreaConfig:initRandomArea(ids, remark)
    RandomUtil:setRandomSeed()
    local data = {}
    local index = 0
    for _, id in pairs(ids) do
        index = index + 1
        table.insert(data, tonumber(index))
    end
    RandomUtil:initRandomSeed(remark, data)
end